import { describe, it, expect } from "vitest";
import { runScenario } from "./claim-office.js";

describe("MHPCO Claim Office", () => {
  // --- Edge cases: empty / simplest premiums ---
  it.todo("empty item list -> premium 5 G (processing fee only)");
  it.todo("quote single sword -> premium 100 + 10 first insurance + 5 fee = 115 G");
  it.todo("quote single amulet -> premium 60 + 6 first insurance + 5 fee = 71 G (rounded up)");
  it.todo("quote single staff -> premium 80 + 8 first insurance + 5 fee = 93 G");
  it.todo("quote single potion -> premium 40 + 4 first insurance + 5 fee = 49 G");

  // --- Components and building blocks ---
  it.todo("2 runes -> 50 G base premium (then first insurance + fee)");
  it.todo("3 runes -> 60 G base premium (block applies)");
  it.todo("4 runes -> 100 G base premium (no block; block requires exactly 3)");
  it.todo("7 runes -> 175 G base premium (3 of them form block 60, plus 4*25 = 100, total 160? Actually 7 runes -> 175 G per spec)");
  it.todo("2 runes + 1 moonstone -> 75 G base premium (no block: different types)");
  it.todo("3 runes + 3 moonstones -> 120 G base premium (two separate blocks)");

  // --- Item-specific modifiers in isolation ---
  it.todo("cursed sword adds 50% surcharge on cursed item (50 G)");
  it.todo("high-enchantment sword (level 5) adds 30% surcharge (30 G)");
  it.todo("sword with enchantment 4 -> no high-enchantment surcharge");
  it.todo("cursed sword with enchantment 5 -> both surcharges apply");

  // --- Policy-wide modifiers ---
  it.todo("long-standing customer (2 years exactly) -> 20% loyalty discount");
  it.todo("first insurance surcharge of 10% on every item in quote");
  it.todo("follow-up contract -> 15% discount on second quote");

  // --- Rounding ---
  it.todo("premium 197.5 G -> rounded up to 198 G");

  // --- Multi-item: modifier scope ---
  it.todo("cursed sword + plain amulet -> base 160, cursed +50, etc.");

  // --- Integration: newcomer with a cursed sword ---
  it.todo("newcomer (0 years, first contract) with cursed sword (steel, enchantment 3) -> premium 165 G");

  // --- Integration: long-standing customer second contract ---
  it.todo("3-year customer's second quote, cursed sword steel enchantment 7 -> premium 160 G");

  // --- Unknown item type in quote -> non-zero exit ---
  it.todo("quote with unknown item type (broomstick) -> CLI exits non-zero, no results on stdout");

  // --- Claims: standard reimbursement ---
  it.todo("standard sword (steel, enchantment 3), damage 500 -> payout 400 (500 - 100 deductible)");
  it.todo("rune damage 200 -> payout 100 (200 - 100 deductible)");

  // --- Claims: high enchantment clause ---
  it.todo("dragon-material sword, enchantment 8, damage 1000 -> payout 400 (high-enchantment 50% then deductible)");
  it.todo("steel sword, enchantment 9, damage 1000 -> payout 400 (50% then deductible)");

  // --- Claims: dragon material clause ---
  it.todo("dragon-material sword, enchantment 5, damage 800 -> payout 700 (full reimbursement then deductible)");
  it.todo("dragon-material sword, enchantment 9, damage 1000 -> payout 400 (50% then deductible)");

  // --- Claims: deductible per damage event ---
  it.todo("dragon attack damages sword 500 + amulet 300 -> payout 600 (100 deductible per item)");

  // --- Claims: rounding payout ---
  it.todo("payout 350.5 -> rounded down to 350");

  // --- Claims: multiple items of same type ---
  it.todo("policy covers two swords -> insurance sum 2000, cap 4000");
  it.todo("two-sword policy, both damaged -> each damage gets its own deductible");
  it.todo("two-sword damages but only one sword insured -> CLI exits non-zero");

  // --- Claims: cap exhaustion ---
  it.todo("sword + amulet -> insurance sum 1600, cap 3200");
  it.todo("cursed sword -> cap 2000 based on unmodified insurance value");
  it.todo("sword + 3 runes (block) -> insurance sum 1750");
  it.todo("sword insured (cap 2000), two claims of 1500 each -> first payout 1400 (cap 600), second payout 600 (cap 0)");

  // --- Claims: errors ---
  it.todo("claim references damage item not part of policy -> CLI exits non-zero");
  it.todo("claim with negative damage amount -> CLI exits non-zero");

  // --- CLI smoke test ---
  it.todo("CLI: full schema example with amulet quote + claim works end-to-end");
});

export function runScenario(_input: unknown): unknown {
  throw new Error("not implemented");
}

