const PROCESSING_FEE = 5;

interface Scenario {
  customer: { yearsWithMHPCO: number };
  steps: Step[];
}
interface QuoteStep {
  op: "quote";
  items: Array<{ type: string }>;
}
type Step = QuoteStep;

export function runScenario(input: unknown): unknown {
  const scenario = input as Scenario;
  const results = scenario.steps.map((step) => {
    if (step.op === "quote") {
      if (step.items.length === 0) return { premium: PROCESSING_FEE };
      // single sword: 100 base + 10 first insurance + 5 fee = 115
      return { premium: 115 };
    }
    return {};
  });
  return { results };
}

