```typescript
function quotePremium(items: Array<{ type: string }>): number {
  const baseSum = items.reduce((sum, item) => sum + BASE_PREMIUMS[item.type], 0);
  const firstInsuranceSurcharge = baseSum * FIRST_INSURANCE_SURCHARGE_RATE;
  return Math.ceil(baseSum + firstInsuranceSurcharge + PROCESSING_FEE);
}

export function runScenario(input: unknown): unknown {
  const scenario = input as Scenario;
  const results = scenario.steps.map((step) => {
    if (step.op === "quote") {
      return { premium: quotePremium(step.items) };
    }
    return {};
  });
  return { results };
}
