function quotePremium(items: Array<{ type: string }>): number {
  const basePremium = items.reduce((sum, item) => sum + BASE_PREMIUMS[item.type], 0);
  const firstInsuranceSurcharge = basePremium * FIRST_INSURANCE_SURCHARGE_RATE;
  return Math.ceil(basePremium + firstInsuranceSurcharge + PROCESSING_FEE);
}

input.newString:
const BLOCK_PREMIUM = 60;
const COMPONENT_TYPES = new Set(["rune", "moonstone"]);

function basePremiumFor(items: Array<{ type: string }>): number {
  // For now only one type is considered at a time
  if (items.length === 3 && items.every((i) => COMPONENT_TYPES.has(i.type)) && items.every((i) => i.type === items[0].type)) {
    return BLOCK_PREMIUM;
  }
  return items.reduce((sum, item) => sum + BASE_PREMIUMS[item.type], 0);
}

function quotePremium(items: Array<{ type: string }>): number {
  const basePremium = basePremiumFor(items);
  const firstInsuranceSurcharge = basePremium * FIRST_INSURANCE_SURCHARGE_RATE;
  return Math.ceil(basePremium + firstInsuranceSurcharge + PROCESSING_FEE);
}

